:root {
  --bg-color: #1e1e1e;
  --sidebar-bg: #252526;
  --toolbar-bg: #333333;
  --border-color: #3c3c3c;
  --text-color: #cccccc;
  --text-secondary: #888888;
  --accent-color: #0078d4;
  --hover-bg: #2a2d2e;
  --selected-bg: #094771;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body, #root {
  height: 100%;
  width: 100%;
  overflow: hidden;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'Segoe UI', Roboto, sans-serif;
  font-size: 13px;
  color: var(--text-color);
  background: var(--bg-color);
}

.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: var(--text-secondary);
}

.app {
  display: flex;
  flex-direction: column;
  height: 100%;
  background: var(--bg-color);
}

/* Toolbar */
.toolbar {
  flex-shrink: 0;
  height: 52px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  padding: 0 12px;
  -webkit-app-region: drag;
}

.toolbar button {
  -webkit-app-region: no-drag;
}

/* Path Bar */
.path-bar {
  display: flex;
  align-items: center;
  gap: 16px;
  width: 100%;
}

.path-bar-nav {
  flex-shrink: 0;
}

.path-bar-breadcrumb {
  display: flex;
  align-items: center;
  background: var(--bg-color);
  border-radius: 6px;
  padding: 6px 12px;
  font-size: 12px;
  overflow: hidden;
  flex: 1;
}

.path-part {
  display: flex;
  align-items: center;
}

.path-separator {
  margin: 0 6px;
  color: var(--text-secondary);
}

.path-name {
  color: var(--text-color);
}

/* Main Content */
.main-content {
  display: flex;
  flex: 1;
  overflow: hidden;
}

/* Sidebar */
.sidebar-container {
  width: 200px;
  flex-shrink: 0;
  background: var(--sidebar-bg);
  border-right: 1px solid var(--border-color);
  overflow-y: auto;
}

.sidebar {
  padding: 8px 0;
}

.sidebar-section {
  margin-bottom: 16px;
}

.sidebar-header {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  color: var(--text-secondary);
  padding: 8px 16px 4px;
  letter-spacing: 0.5px;
}

/* File List */
.file-list-container {
  flex: 1;
  overflow: auto;
  background: var(--bg-color);
}

/* Terminal */
.terminal-container {
  width: 400px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  border-left: 1px solid var(--border-color);
  background: #1e1e1e;
}

.terminal-header {
  flex-shrink: 0;
  height: 32px;
  display: flex;
  align-items: center;
  padding: 0 12px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border-color);
}

.terminal-path {
  font-size: 11px;
  color: var(--text-secondary);
  font-family: 'SF Mono', Menlo, Monaco, monospace;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Ring UI overrides for dark theme */
.ring-ui-theme-dark {
  --ring-content-background-color: var(--bg-color);
  --ring-popup-background-color: var(--sidebar-bg);
  --ring-text-color: var(--text-color);
  --ring-secondary-color: var(--text-secondary);
  --ring-line-color: var(--border-color);
  --ring-borders-color: var(--border-color);
}

/* Table styles */
[class*="ring-table"] {
  background: transparent !important;
}

[class*="ring-table"] th {
  background: var(--toolbar-bg) !important;
  color: var(--text-secondary) !important;
  font-weight: 500 !important;
  font-size: 11px !important;
  text-transform: uppercase !important;
  letter-spacing: 0.5px !important;
}

[class*="ring-table"] td {
  color: var(--text-color) !important;
  border-color: var(--border-color) !important;
}

[class*="ring-table"] tr:hover td {
  background: var(--hover-bg) !important;
}

[class*="ring-table"] tr[class*="checked"] td,
[class*="ring-table"] tr[class*="selected"] td {
  background: var(--selected-bg) !important;
}

/* List styles */
[class*="ring-list"] {
  background: transparent !important;
}

[class*="ring-list-item"]:hover {
  background: var(--hover-bg) !important;
}

[class*="ring-list-item"].selected {
  background: var(--selected-bg) !important;
}

/* Button styles */
[class*="ring-button"] {
  background: var(--toolbar-bg) !important;
  border-color: var(--border-color) !important;
  color: var(--text-color) !important;
}

[class*="ring-button"]:hover {
  background: var(--hover-bg) !important;
}

[class*="ring-button"]:disabled {
  opacity: 0.5;
}

/* Scrollbar */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #555;
}

use std::env;

#[tauri::command]
fn get_home_dir() -> String {
    env::var("HOME").unwrap_or_else(|_| "/".to_string())
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_shell::init())
        .plugin(tauri_plugin_fs::init())
        .invoke_handler(tauri::generate_handler![get_home_dir])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

